var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조심하세요, 실키. 여긴 계단이 가파릅니다.","JPN":"気をつけてください、シルキー。ここの階段は急ですわ。","ENG":"Be careful Sylkie, the stairs here are steep.","TWN":"小心點，思琪。這裡的樓梯很陡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"너무 어두워서 얼마나 내려왔는지도 모르겠어요.","JPN":"暗すぎて、どれくらい降りてきたかもわかりませんね。","ENG":"It's so dark, I can't see how far I've come down.","TWN":"太黑了，不知道往底下走了多少。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"총소리도…… 더는 들리지 않아요.","JPN":"銃声も……もう聞こえません。","ENG":"The gunshots... I don't hear them anymore.","TWN":"槍聲……也聽不見了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"이 지하에 부학회장님의 힘을 되찾을 방법이 있는 건가요?","JPN":"この地下に、副学会長様の力を取り戻す方法があるんですか？","ENG":"Is the basement where you're going to regain your powers, ma'am?","TWN":"這地下有能找回副學會長力量的辦法嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래요. 여기가 아니면 안 돼요.","JPN":"そうですわ。ここでないといけません。","ENG":"Yes, and this is the only place where I can.","TWN":"是的，只有這裡可以。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"생각해 보면 이상하지 않나요?","JPN":"考えてみたら、おかしくないですか？","ENG":"Do you not find it odd?","TWN":"想想不覺得奇怪嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 갑자기 힘이 약해지는 바람에 학회원들 상대로도 쩔쩔 매는 처지였어요.","JPN":"私は突然力が弱まり、学会員の相手をするだけでも大変でした。","ENG":"I had become so weak that I could not even defend myself against the Society members.","TWN":"因為我的力量突然變弱，所以面對學會成員也手足無措。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데도 결국 힘을 되찾아야겠다는 생각은 전혀 안 했죠.","JPN":"それなのに力を取り戻そうとはまったく考えませんでしたわ。","ENG":"Nevertheless, I never thought to get my powers back.","TWN":"但即便如此，我還是完全沒想過要找回力量。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델을 찾아가는 와중에 무슨 일이 생길 줄 모르는데도 말입니다.","JPN":"エデルを訪ねていく途中でどんなことが起きるかもわからないのにです。","ENG":"Even though I did not know what would happen as I searched for Edel.","TWN":"即便在尋找艾瑟兒的過程中，我不知道會發生什麼事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"어……?","JPN":"え……？","ENG":"Huh...?","TWN":"呃……？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그렇네요. 전 시간이 없어서 서두르신 줄 알았어요.","JPN":"そういえばそうですね。時間がないから急いでいるのかと思っていました。","ENG":"You're right. I assumed you were rushing because you didn't have time.","TWN":"是啊，我還以為是因為沒時間，你太著急了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"그럼… 왜 그러셨을까요?","JPN":"じゃあ……どうしてですか？","ENG":"Then... what was the real reason?","TWN":"那……為什麼會這樣呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님은 수도원에서 제 기억에 혼선이 일어났다고 하셨습니다.","JPN":"社長は修道院で、私の記憶が混乱しているとおっしゃいました。","ENG":"Boss informed me that my memories had become jumbled at the monastery.","TWN":"在修道院裡，老闆說我的記憶出現了混亂。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"심리적인 이유로, 무의식이 떠올리기를 거부한다는 추론이었죠.","JPN":"心理的な理由で、無意識に思い出すことを拒んでいるという推論でした。","ENG":"He assumed it was psychological, and my subconscious was refusing to recall them.","TWN":"他推斷我是因為心理上的原因，下意識地拒絕想起來。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"네. 회동에서 있었던 일 때문에 학회와 관련된 일은 떠올리기 싫어하신다고……","JPN":"はい。会合での出来事のせいで、学会に関することを思い出したくないと思っているって……","ENG":"Yes. He said something about you not wanting to remember what happened back at the meeting...","TWN":"是的。他說你因為會議的事，拒絕想起與學會有關的事……"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"빈정 상해서 며칠 동안 방에 틀어박혀 있었죠.","JPN":"腹が立って、何日も部屋に引きこもっていましたわ。","ENG":"I was upset so I locked myself in my room for days on.","TWN":"因為傷心，我在房間裡待了好幾天。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"바꿔 말하면, 회동에서 실패한 건 저에게 그 정도였어요.","JPN":"言ってみれば、会合で失敗した件はその程度のことだったのです。","ENG":"In other words, the failure of the meeting was just that much to me.","TWN":"換句話說，在會議上失敗的事，對我來說只是那種程度而已。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"학회가 원래 광인들의 소굴이라는 사실은 알고 있었으니까요.","JPN":"学会がそもそも狂人の巣窟だってことはわかっていましたから。","ENG":"I already knew that the Society was full of lunatics.","TWN":"因為我知道學會本來就是一群瘋子的聚集地。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대학원에서 논문을 물어뜯는 승냥이들을 상대하다 보면, 그런 경우는 비일비재하고요.","JPN":"大学院で論文に難癖をつける人たちの相手をしていると、そんなのはよくあることですし。","ENG":"Also, I've already seen many similar cases while I was writing my thesis in graduate school.","TWN":"在研究所裡面對詆毀論文的豺狼們時，那種情況我見的多了。"},"stage":{"bg":"CHURCH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 수도원에서는 은근슬쩍 넘어갔죠.","JPN":"ですが、修道院ではなんともないように過ごしました。","ENG":"But I glossed over something, back at the monastery.","TWN":"不過在修道院，我卻那麼故意略過了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"정말 외면하고 싶던 것은 에델이 말하기 전까지 끝끝내 피하려고 했어요.","JPN":"本当に目を背けたかったことについては、エデルが話すその時まで避けようとしました。","ENG":"What I really did not want to remember was avoided until Edel told me about it.","TWN":"我真正想要逃避的事，在艾瑟兒說之前，我確實一直想逃避。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"의식……. 말씀이세요?","JPN":"儀式の……ことですか？","ENG":"The... ritual, you mean?","TWN":"你是說……儀式嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네. 에델은 영지의 주민들을 희생시켜 저를 되살렸죠.","JPN":"はい。エデルは領地の住民を犠牲にして私を蘇らせました。","ENG":"Yes, Edel sacrificed the residents of the estate to resurrect me.","TWN":"是的，艾瑟兒犧牲了領地居民救活了我。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……바로 이 곳에서요.","JPN":"……まさに、この場所で。","ENG":"…Right here.","TWN":"……就在這個地方。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"저기, 부학회장님. 액자에 걸린 사진들은……","JPN":"あの、副学会長様。額の中の写真は……","ENG":"Um, Ms. Vice President? What are all those pictures on the wall...","TWN":"那個，副學會長，相框裡的照片……"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저희 선조 분들이세요.","JPN":"私の先祖の方々ですわ。","ENG":"They are my ancestors.","TWN":"都是我的祖先。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다들 불경한 지식에 빠져 지내시느라 사교성은 안중에도 없으셨죠.","JPN":"みんな不敬な知識に耽っていて、社交性なんて眼中にもありませんでした。","ENG":"They were all so engrossed in this sacrilegious knowledge that they never gave a damn about socializing.","TWN":"大家都沉醉在不敬的知識中，所以根本不把社交放在眼裡。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……이 분들이 지켜보던 가운데, 저를 위해 많은 사람들이 목숨을 버렸어요.","JPN":"……この方々が見守る中で、私のためにたくさんの人々が命を捨てました。","ENG":"While all of them were watching... many of my people gave their lives for me.","TWN":"……就在這些人的注視下，很多人因為我丟掉了性命。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 저도 알고 있었던 거예요.","JPN":"それに、私もわかっていたのです。","ENG":"And I knew about it.","TWN":"而且，我應該也是知道的。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"주민들의 희생 위에서 살아가야 한다는 걸.","JPN":"住民の犠牲の上に生きていかなければならないということを。","ENG":"I was aware that I had been revived at the expense of the residents.","TWN":"必須在居民們的犧牲中活下去的事實。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그저…… 그 사실을 차마 인정할 수가 없어서 외면해 왔을 뿐이에요.","JPN":"ただ……その事実を認めたくなくて目を背けてきただけです。","ENG":"However... I refused to admit it and buried it deep.","TWN":"只是……不忍心承認這個事實，所以一直在逃避而已。"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ESPR2_06","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 학회에 진저리가 났던 게 아닙니다.","JPN":"私は学会がうんざりだったわけではなかったのですわ。","ENG":"It was not because I was fed up with the Society.","TWN":"我不是厭倦了學會。"},"stage":{"bg":"ESPR2_05","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"희생하는 사람들을 위해 아무것도 못했던 제 자신이……","JPN":"犠牲となる人々のために、何もできなかった私自身が……","ENG":"It was because I could do nothing for all of the people who had given their lives for me...","TWN":"為那些犧牲之人什麼都做不了的自己……"},"stage":{"bg":"ESPR2_05","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지키지 못했던 이들의 몫만큼 살아가야 한다는 책임감이…….","JPN":"守れなかった人々の分まで生きていかなければならないという責任感が……","ENG":"The burden of bearing responsibility for those I was unable to protect...","TWN":"還有必須背負起沒能守護居民們那份責任感……"},"stage":{"bg":"ESPR2_05","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"견딜 수 없을 만큼 두려웠던 거예요.","JPN":"耐えられないほど怖かったのです。","ENG":"It was unbearably terrifying.","TWN":"都讓我害怕到無法承受。"},"stage":{"bg":"ESPR2_05","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 그럴 때, 당신이 나타났죠.","JPN":"そしてその時、あなたが現れました。","ENG":"That is when you appeared.","TWN":"然後就在那時，你就出現了。"},"stage":{"bg":"ESPR2_05","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레지. 나.</color>","JPN":"<color=#ff3636>レジー、ナ。</color>","ENG":"<color=#ff3636>Regi. Na.</color>","TWN":"<color=#ff3636>蕾·佳·娜。</color>"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L2_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"괴, 괴물…….","JPN":"か、怪物……","ENG":"Th-the monster...","TWN":"怪…怪物……"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"어떡하죠? 이제 더 도망칠 곳도 없는데……!","JPN":"どうしましょう？　もう逃げられるところもないのに……！","ENG":"What do we do? There's nowhere to run...!","TWN":"怎麼辦？現在也沒有地方可以逃了……！"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저는 더 이상 도망치지 않아요, 실키.","JPN":"私はもう逃げません、シルキー。","ENG":"We are not running away anymore, Sylkie.","TWN":"我不會再逃了，思琪。"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"하지만…… 부학회장님도 손가락 하나 까딱 못할 만큼 무서워하셨으면서!","JPN":"でも……副学会長様も指一本動かせないほど怖がっていたじゃないですか！","ENG":"But... you were also petrified, not being able to move an inch!","TWN":"可是……副學會長現在害怕得連手指都動不了！"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"학회장님과 겨룰 만큼 무서운 괴물이에요! 도망쳐도 아무도 뭐라고 안 할 거예요!","JPN":"学会長と張り合えるほど恐ろしい怪物です！　逃げたって誰も責めたりしません！","ENG":"That monster is just as terrifying as the President! There is no shame in running away from it!","TWN":"這個怪物可怕到能和學會長一較高下！就算你逃跑也沒人會說什麼的！"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇겠죠.","JPN":"そうでしょうね。","ENG":"That may be true.","TWN":"是啊。"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이 냉기는……. 제 자신.","JPN":"この冷気は……私自身。","ENG":"But that frost... It is mine.","TWN":"這寒氣……就是我自己。"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그리고 저건… 오직 제가 감당해야 할, 죄책감의 산물이니까요.","JPN":"そしてあれは……この私が背負うべき罪責感の産物ですから。","ENG":"And that monster... is the manifestation of the guilt I must bear.","TWN":"而且，這個……就是我應該承受的，罪惡感的產物。"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>레. 지나. 도망. 안. 쳐?</color>","JPN":"<color=#ff3636>レ、ジーナ、ニゲ、ナ、イ？</color>","ENG":"<color=#ff3636>Re. Gina. Not Run. Ning. Away?</color>","TWN":"<color=#ff3636>蕾·佳娜·不·逃·跑嗎？</color>"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHASER_NPC_ESPR2_NULL","text":{"KOREA":"<color=#ff3636>기쁘. 다.</color>","JPN":"<color=#ff3636>ウレシ、イ。</color>","ENG":"<color=#ff3636>I'm so. Glad.</color>","TWN":"<color=#ff3636>好·開·心。</color>"},"stage":{"bg":"UNDER","bgm":"THEMA_CA_REGINA_PART_A","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHASER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};